SELECT vehicle_id, AVG(year) AS average_sales_year
FROM vehicle_sales
GROUP BY vehicle_id;

SELECT vehicle_id
FROM vehicle_performance
WHERE zero_to_sixty_time > 9;

SELECT make_name, country_of_origin, website
FROM makes
WHERE make_id = 1;

SELECT vehicle_id, final_price
FROM vehicle_pricing
WHERE discount > 0.1 AND final_price > 16000;

SELECT vehicle_id, AVG(final_price) AS average_final_price
FROM vehicle_pricing
GROUP BY vehicle_id;

SELECT vehicle_id, SUM(cost) AS total_cost
FROM vehicle_service
GROUP BY vehicle_id;

SELECT part_name, availability
FROM vehicle_parts
ORDER BY cost DESC;

SELECT engine_type_name, valvetrain_design
FROM engine_types
WHERE engine_type_id IN (0, 1);

SELECT u.user_name, al.access_date
FROM users u
JOIN access_logs al ON u.user_id = al.user_id;

SELECT part_name, cost
FROM vehicle_parts
WHERE vehicle_id = 2;

SELECT COUNT(make_id) AS NumberOfVehicles, country_of_origin
FROM makes
GROUP BY country_of_origin;

SELECT COUNT(*) 
FROM vehicle_sales 
WHERE sales_trend = 'up';
